import type { OxlintNodeOptions } from '@teambit/oxc.linter.oxlint-node';
export type OxlintOptions = {
    name?: string;
    /**
     * path to the oxlint binary.
     * Takes precedence over binDir.
     */
    binPath?: string;
    /**
     * path to the tsgolint binary.
     * Takes precedence over binDir.
     */
    tsgolintBinPath?: string;
    /**
     * directory to resolve both oxlint and tsgolint binaries from.
     * Used as a fallback when binPath or tsgolintBinPath are not specified.
     */
    binDir?: string;
    oxlintNodeOptions: OxlintNodeOptions;
    /**
     * file types to lint.
     */
    extensions?: string[];
};
